request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gw ?gwName ?choreo ?modelName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "6c9090aeef814120944b4885c7343b63" ;
         bbo:name ?modelName .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?gw a bboExt:ExclusiveGateway ;
      tai:belongsTo ?choreo .
  OPTIONAL { ?gw bbo:name ?gwName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gw ?gwName ?choreo ?modelName ?modelIdMatch WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         ( tai:normalizedId|tai:originalId ) ?modelIdMatch .
  FILTER(STR(?modelIdMatch) = "6c9090aeef814120944b4885c7343b63")

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?gw a bboExt:ExclusiveGateway ;
      tai:belongsTo ?choreo .

  OPTIONAL { ?gw bbo:name ?gwName . }
}
LIMIT 25
